module.render:
    const gap = args.gap || '1.5rem';
    const align = args.align || 'flex-start';
    const ratioArr = Array.isArray(args.ratio) ? args.ratio : [];
    const divider = String(args.divider) === 'true';
    const wrap = String(args.wrap) === 'true';
    const pad = args.pad && String(args.pad).trim();
    const dividerColor = args.dividerColor && String(args.dividerColor).trim();
    const cls = 'mdp-mod-multicolumn' + (divider ? ' mdp-has-divider' : '');
    let cstyle = `gap: ${gap}; align-items: ${align};`;
    if (wrap) cstyle += ' flex-wrap: wrap;';
    if (dividerColor) cstyle += ` --mc-divider: ${dividerColor};`;
    let html = `\n\n<div class="${cls}" style="${cstyle}">\n`;
    sections.forEach((section, index) => {
       const contentStr = section.trim();
       if (!contentStr) return;
       const flexRatio = ratioArr[index] !== undefined && ratioArr[index] !== '' ? ratioArr[index] : '1';
       const colStyle = `flex: ${flexRatio};` + (pad ? ` padding: ${pad};` : '');
       html += `<div class="mdp-mod-column" style="${colStyle}">

${contentStr}

</div>`;
    });
    html += `</div>\n\n`;
    return html;
